import hashlib
import json
from pathlib import Path


class EmbeddingCache:
    def __init__(self, cache_path: str):
        self.path = Path(cache_path)
        self._data: dict[str, list[float]] = {}
        if self.path.exists():
            self._data = json.loads(self.path.read_text())

    def _key(self, text: str) -> str:
        return hashlib.sha256(text.encode()).hexdigest()

    def get(self, text: str) -> list[float] | None:
        return self._data.get(self._key(text))

    def set(self, text: str, vec: list[float]) -> None:
        self._data[self._key(text)] = vec
        self.path.write_text(json.dumps(self._data))


cache = EmbeddingCache(".embed_cache.json")


def embed_with_cache(
    texts: list[str],
    input_type: str = "document",
) -> list[list[float]]:
    results: list[list[float] | None] = [cache.get(t) for t in texts]
    missing_indices = [i for i, v in enumerate(results) if v is None]
    if missing_indices:
        missing_texts = [texts[i] for i in missing_indices]
        new_vecs = embed_texts(missing_texts, input_type=input_type)
        for i, vec in zip(missing_indices, new_vecs):
            results[i] = vec
            cache.set(texts[i], vec)
    return results   # type: ignore[return-value]
